import * as Notifications from 'expo-notifications';
import { Platform } from 'react-native';
import { Audio, InterruptionModeIOS, InterruptionModeAndroid } from 'expo-av';
let SystemSetting: { setVolume?: (v: number) => void } | null = null;
try {
  SystemSetting = // eslint-disable-next-line @typescript-eslint/no-require-imports
    (require('react-native-system-setting') as { default: { setVolume?: (v: number) => void } })
      .default;
} catch {}
import type { SleepSchedule } from '../api/local';

// ── Fixed sounds per alarm type ───────────────────────────────────────────────
// Wake Up  — upbeat, energetic rising tone
// Bedtime  — soft, calming ambient chime

const SOUNDS: Record<'alarm' | 'bedtime', string> = {
  alarm:
    'data:audio/wav;base64,',
  bedtime:
    'data:audio/wav;base64,',
};

export function getSoundForType(type: 'alarm' | 'bedtime'): string {
  return SOUNDS[type];
}

// ── Notification foreground handler ──────────────────────────────────────────
Notifications.setNotificationHandler({
  handleNotification: async () => ({
    shouldShowAlert: true,
    shouldPlaySound: true,
    shouldSetBadge: false,
    shouldShowBanner: true,
    shouldShowList: true,
  }),
});

// ── Android alarm channel ─────────────────────────────────────────────────────
export async function setupAlarmChannel(): Promise<void> {
  if (Platform.OS !== 'android') return;
  await Notifications.setNotificationChannelAsync('alarms', {
    name: 'Alarms',
    importance: Notifications.AndroidImportance.MAX,
    sound: 'alarm.wav',
    vibrationPattern: [0, 500, 200, 500],
    bypassDnd: true,
    lockscreenVisibility: Notifications.AndroidNotificationVisibility.PUBLIC,
    enableVibrate: true,
    enableLights: true,
    lightColor: '#7C3AED',
  });
}

// ── Permissions ───────────────────────────────────────────────────────────────
export async function requestNotificationPermission(): Promise<boolean> {
  await setupAlarmChannel();
  const { status } = await Notifications.requestPermissionsAsync({
    ios: {
      allowAlert: true,
      allowSound: true,
      allowBadge: false,
      allowCriticalAlerts: true,
    },
  });
  return status === 'granted';
}

// ── In-app looping alarm sound ────────────────────────────────────────────────
let _sound: Audio.Sound | null = null;
let _prevVolume: number | null = null; // volume before alarm, restored on dismiss

export async function playAlarmSound(type: 'alarm' | 'bedtime' = 'alarm'): Promise<void> {
  try {
    await Audio.setAudioModeAsync({
      allowsRecordingIOS: false,
      staysActiveInBackground: true,
      playsInSilentModeIOS: true, // bypass iOS silent/ringer switch
      interruptionModeIOS: InterruptionModeIOS.DoNotMix,
      shouldDuckAndroid: false,
      interruptionModeAndroid: InterruptionModeAndroid.DoNotMix,
      playThroughEarpieceAndroid: false,
    });

    // Save current volume, then force to max (only if native module available)
    try {
      if (SystemSetting) {
        _prevVolume = (await SystemSetting.getVolume('music')) as number;
        if ((_prevVolume as number) < 0.8) {
          await SystemSetting.setVolume(1.0, { type: 'music', showUI: false });
        }
      }
    } catch {}

    if (_sound) {
      await _sound.stopAsync().catch(() => {});
      await _sound.unloadAsync().catch(() => {});
      _sound = null;
    }

    const { sound } = await Audio.Sound.createAsync(
      { uri: getSoundForType(type) },
      { shouldPlay: true, isLooping: true, volume: 1.0 }
    );
    _sound = sound;
  } catch (e) {
    console.warn('[AlarmSound] Failed to play:', e);
  }
}

export async function stopAlarmSound(): Promise<void> {
  if (_sound) {
    try {
      await _sound.stopAsync();
      await _sound.unloadAsync();
    } catch {}
    _sound = null;
  }
  // Restore volume to what it was before the alarm
  try {
    if (SystemSetting && _prevVolume != null) {
      await SystemSetting.setVolume(_prevVolume as number, { type: 'music', showUI: false });
    }
  } catch {}
  _prevVolume = null;
  // Reset audio mode back to normal
  try {
    await Audio.setAudioModeAsync({
      allowsRecordingIOS: false,
      staysActiveInBackground: false,
      playsInSilentModeIOS: false,
      interruptionModeIOS: InterruptionModeIOS.MixWithOthers,
      shouldDuckAndroid: true,
      interruptionModeAndroid: InterruptionModeAndroid.DuckOthers,
      playThroughEarpieceAndroid: false,
    });
  } catch {}
}

export function isAlarmPlaying(): boolean {
  return _sound !== null;
}

// ── Schedule / cancel notifications ──────────────────────────────────────────
export async function scheduleAlarmNotification(item: SleepSchedule): Promise<void> {
  await cancelAlarmNotification(item.id);
  if (!item.enabled) return;

  const [h, m] = item.time.split(':').map(Number);
  const isAlarm = item.type === 'alarm';
  const title = isAlarm ? '⏰ Wake Up' : '🌙 Bedtime';
  const body = isAlarm ? `Time to wake up! — ${item.label}` : `Time to wind down — ${item.label}`;

  const days = item.days ?? [];
  const repeat = item.repeat ?? true;

  // Use bundled sound file — plays natively even on lock screen without JS
  const soundFile = isAlarm ? 'alarm.wav' : 'bedtime.wav';

  const content: Notifications.NotificationContentInput = {
    title,
    body,
    sound: soundFile,
    data: { scheduleId: item.id, type: item.type },
    ...(Platform.OS === 'android' && { channelId: 'alarms' }),
    ...(item.vibrate && { vibrate: [0, 500, 200, 500] }),
  };

  if (repeat && days.length > 0) {
    for (const day of days) {
      await Notifications.scheduleNotificationAsync({
        identifier: `${item.id}_day${day}`,
        content,
        trigger: {
          type: Notifications.SchedulableTriggerInputTypes.WEEKLY,
          weekday: day + 1,
          hour: h,
          minute: m,
        },
      });
    }
  } else if (repeat) {
    await Notifications.scheduleNotificationAsync({
      identifier: item.id,
      content,
      trigger: { type: Notifications.SchedulableTriggerInputTypes.DAILY, hour: h, minute: m },
    });
  } else {
    const fire = new Date();
    fire.setHours(h, m, 0, 0);
    if (fire <= new Date()) fire.setDate(fire.getDate() + 1);
    await Notifications.scheduleNotificationAsync({
      identifier: item.id,
      content,
      trigger: { type: Notifications.SchedulableTriggerInputTypes.DATE, date: fire },
    });
  }
}

export async function cancelAlarmNotification(id: string): Promise<void> {
  await Notifications.cancelScheduledNotificationAsync(id).catch(() => {});
  for (let day = 0; day < 7; day++) {
    await Notifications.cancelScheduledNotificationAsync(`${id}_day${day}`).catch(() => {});
  }
}
